// ==================== USER COLLECTION ====================

/**
 * Collection Name: users
 * Purpose: Store all user information (admin, staff, regular users)
 * 
 * Field Definitions:
 * - _id (ObjectId): Unique identifier, auto-generated by MongoDB
 * - name (String): User's full name, required
 * - email (String): User's email, unique, lowercase, required
 * - password (String): Bcrypted password, required (never sent in responses)
 * - phone (String): Phone number, required
 * - vehicleNumber (String): Vehicle registration number, optional (for users only)
 * - role (String): User role - 'admin', 'staff', or 'user'
 * - isActive (Boolean): Account status, default: true
 * - totalSpent (Number): Total amount spent on parking, default: 0
 * - createdAt (Date): Account creation timestamp
 * - updatedAt (Date): Last update timestamp
 * 
 * Indexes:
 * - email (unique)
 * - role
 * - isActive
 */

// Sample Admin Document
const ADMIN_DOCUMENT = {
  _id: { $oid: "000000000000000000000001" },
  name: "System Administrator",
  email: "admin@campus.edu",
  password: "$2a$12$...",  // Hashed - never readable
  phone: "9876543210",
  role: "admin",
  isActive: true,
  totalSpent: 0,
  createdAt: { $date: "2024-01-01T00:00:00Z" },
  updatedAt: { $date: "2024-01-01T00:00:00Z" }
};

