// ==================== PARKING SLOTS COLLECTION ====================

/**
 * Collection Name: parkingslots
 * Purpose: Store parking slot information
 * 
 * Field Definitions:
 * - _id (ObjectId): Unique identifier
 * - slotNumber (String): Slot identifier (e.g., "A01"), unique
 * - zone (String): Zone (A, B, C, D)
 * - floor (Number): Floor number (1 or 2)
 * - type (String): Slot type - 'standard', 'compact', 'handicapped', 'ev_charging'
 * - pricePerHour (Number): Hourly rate in rupees
 * - status (String): Current status - 'available', 'booked', 'occupied', 'maintenance'
 * - createdAt (Date): Creation timestamp
 * - updatedAt (Date): Last update timestamp
 * 
 * Default Setup:
 * - 4 zones: A, B, C, D
 * - 15 slots per zone = 60 total slots
 * - Pricing:
 *   - Handicapped: ₹10/hr (Slot 1 of each zone)
 *   - EV Charging: ₹30/hr (Slot 2 of each zone)
 *   - Compact: ₹15/hr (Slots 3-6 of each zone)
 *   - Standard: ₹20/hr (Slots 7-15 of each zone)
 */

// Sample Parking Slot Document
const PARKING_SLOT_DOCUMENT = {
  _id: { $oid: "000000000000000000000100" },
  slotNumber: "A01",
  zone: "A",
  floor: 1,
  type: "handicapped",
  pricePerHour: 10,
  status: "available",
  createdAt: { $date: "2024-01-01T00:00:00Z" },
  updatedAt: { $date: "2024-01-01T00:00:00Z" }
};

// ==================== BOOKINGS COLLECTION ====================

/**
 * Collection Name: bookings
 * Purpose: Store parking booking information
 * 
 * Field Definitions:
 * - _id (ObjectId): Unique identifier
 * - userId (ObjectId): Reference to user document
 * - slotId (ObjectId): Reference to parking slot document
 * - vehicleNumber (String): Vehicle number
 * - checkInTime (Date): When vehicle checked in / booking time
 * - checkOutTime (Date): When vehicle checked out, optional
 * - estimatedDuration (Number): Estimated duration in hours
 * - status (String): Status - 'pending', 'active', 'checked_in', 'completed', 'cancelled'
 * - totalAmount (Number): Total parking charges
 * - paymentMethod (String): Payment method - 'cash', 'card', 'upi', 'wallet'
 * - createdAt (Date): Booking creation timestamp
 * - updatedAt (Date): Last update timestamp
 * 
 * Status Lifecycle:
 * 1. pending - Booking created, waiting to start
 * 2. active - Vehicle is actively using the slot
 * 3. checked_in - Staff has verified check-in
 * 4. completed - Vehicle has checked out, payment done
 * 5. cancelled - Booking was cancelled before completion
 */

// Sample Booking Document
const BOOKING_DOCUMENT = {
  _id: { $oid: "000000000000000000000200" },
  userId: { $oid: "000000000000000000000003" },
  slotId: { $oid: "000000000000000000000100" },
  vehicleNumber: "UP32AB1234",
  checkInTime: { $date: "2024-01-15T10:00:00Z" },
  checkOutTime: { $date: "2024-01-15T12:00:00Z" },
  estimatedDuration: 2,
  status: "completed",
  totalAmount: 40,
  paymentMethod: "card",
  createdAt: { $date: "2024-01-15T10:00:00Z" },
  updatedAt: { $date: "2024-01-15T12:00:00Z" }
};

