// ==================== ROLE-BASED PERMISSIONS ====================

/**
 * ADMIN ROLE Permissions:
 * ✓ View all users
 * ✓ Create new users (any role)
 * ✓ Update user information
 * ✓ Deactivate/Activate users
 * ✓ View all bookings
 * ✓ Create/Update/Delete parking slots
 * ✓ View revenue analytics
 * ✓ Access admin dashboard
 * ✓ View system metrics
 * 
 * Endpoints:
 * - GET /api/admin/users
 * - POST /api/admin/users
 * - PUT /api/admin/users/:id
 * - GET /api/admin/dashboard
 * - GET /api/admin/revenue
 * - PUT /api/slots/:id/price
 * - POST /api/slots
 * - DELETE /api/slots/:id
 */

/**
 * STAFF ROLE Permissions:
 * ✓ View active bookings
 * ✓ Perform check-in operations
 * ✓ Perform check-out operations
 * ✓ Calculate billing
 * ✓ Search vehicles
 * ✓ Record parking receipts
 * 
 * Endpoints:
 * - GET /api/staff/active-bookings
 * - POST /api/staff/checkin/:id
 * - POST /api/staff/checkout/:id
 * - GET /api/staff/search?vehicleNumber=...
 */

/**
 * USER ROLE Permissions:
 * ✓ View own profile
 * ✓ View available parking slots
 * ✓ Create booking
 * ✓ View own bookings
 * ✓ Cancel own bookings
 * ✓ View active booking details
 * ✓ Update profile
 * 
 * Endpoints:
 * - GET /api/auth/me
 * - PUT /api/auth/profile
 * - GET /api/slots
 * - GET /api/slots/available
 * - POST /api/bookings
 * - GET /api/bookings/my
 * - GET /api/bookings/active
 * - PUT /api/bookings/:id/cancel
 */

