// ==================== STEPS TO ADD NEW USERS ====================

/**
 * METHOD 1: Using the Application Frontend (Recommended)
 * ======================================================
 * 1. Navigate to http://localhost:3000
 * 2. Click "Register" tab on login page
 * 3. Fill in details:
 *    - Name: Full name
 *    - Email: Unique email address
 *    - Password: At least 8 characters
 *    - Phone: 10 digit number
 *    - Vehicle: Vehicle registration number
 * 4. Click "Register"
 * 5. User can now login
 * 
 * METHOD 2: Using API (For Automation)
 * =====================================
 * POST http://localhost:5000/api/auth/register
 * Content-Type: application/json
 * 
 * {
 *   "name": "New User",
 *   "email": "newuser@campus.edu",
 *   "password": "SecurePass@123",
 *   "phone": "9876543220",
 *   "vehicleNumber": "HR26AB1234"
 * }
 * 
 * METHOD 3: Using Node.js Script
 * ===============================
 * Run: node backend/config/addUser.js
 * Then follow interactive prompts to add users
 * 
 * METHOD 4: Using MongoDB Compass
 * ================================
 * 1. Open MongoDB Compass
 * 2. Connection: Use credentials from .env (MONGO_URI)
 * 3. Database: smart_parking
 * 4. Collection: users
 * 5. Click "+INSERT DOCUMENT"
 * 6. Add user data (note: password won't be hashed in direct insert)
 * 
 * METHOD 5: Using mongosh CLI
 * ============================
 * mongosh "<your_mongodb_connection_string>"
 * use smart_parking
 * db.users.insertOne({ ...user data... })
 */

// ==================== PASSWORD REQUIREMENTS ====================

/**
 * Password Policy:
 * - Minimum length: 8 characters
 * - Recommended: Include uppercase, lowercase, number, special character
 * - Storage: Bcrypted with 12 salt rounds
 * - Transmission: Only over HTTPS in production
 * 
 * Valid Examples:
 * - Admin@12345
 * - Staff@12345
 * - User@123456
 * - SecurePass@2024
 * - Password123!
 * 
 * Invalid Examples:
 * - password (no uppercase, numbers, special char)
 * - Pass12 (too short)
 * - 12345678 (no letters)
 */

// ==================== VEHICLE NUMBER FORMAT ====================

/**
 * Vehicle Number Patterns (Indian):
 * - Format: XX##XX#### or XX##XX####
 * - Examples:
 *   - UP32AB1234 (Uttar Pradesh)
 *   - DL01CD5678 (Delhi)
 *   - MH02EF9012 (Maharashtra)
 *   - KA01GH3456 (Karnataka)
 *   - TN02IJ5678 (Tamil Nadu)
 * 
 * Field Characteristics:
 * - Stored in uppercase
 * - Optional for admin and staff users
 * - Required for regular users
 * - Used for vehicle search and tracking
 */

// ==================== COMMON MONGODB OPERATIONS ====================

/**
 * View all users in a collection:
 * db.users.find()
 * 
 * Count total users:
 * db.users.countDocuments()
 * 
 * Find specific user:
 * db.users.findOne({ email: "admin@campus.edu" })
 * 
 * Update user:
 * db.users.updateOne(
 *   { email: "admin@campus.edu" },
 *   { $set: { isActive: false } }
 * )
 * 
 * Delete user:
 * db.users.deleteOne({ email: "test@campus.edu" })
 * 
 * Count by role:
 * db.users.aggregate([
 *   { $group: { _id: "$role", count: { $sum: 1 } } }
 * ])
 */

